CREATE TABLE IF NOT EXISTS watchlist_entities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL UNIQUE, aliases text[] NOT NULL DEFAULT '{}', category text NOT NULL CHECK (category IN ('issuer', 'payments', 'institutional', 'regulatory', 'infrastructure', 'enterprise', 'rwa', 'defi')), active boolean NOT NULL DEFAULT true, metadata jsonb DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
